import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        // Split on whitespace or literal "\\n" sequences that may appear in the input string
        sc.useDelimiter("\\s+|\\\\n");
        if (!sc.hasNextInt()) return;
        int T = sc.nextInt();
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            PriorityQueue<Integer> pq = new PriorityQueue<>(k);
            for (int i = 0; i < n; i++) {
                int v = sc.nextInt();
                if (pq.size() < k) {
                    pq.offer(v);
                } else if (v > pq.peek()) {
                    pq.poll();
                    pq.offer(v);
                }
            }
            sb.append(pq.peek());
            if (t != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

